import dgram from 'dgram';
import net from 'net';
import { EventEmitter } from 'events';
import type { Socket } from 'dgram';
import type { Server } from 'net';

export interface Logger {
  log: (entry: { type: number; msg: string }) => void;
}

export interface PiperStats {
  rejectCnt?: number;
  locCnt?: number;
  remCnt?: number;
}

export interface PiperOptions {
  logger?: Logger;
  onDestroy?: (err?: Error) => void;
  isServer?: boolean;
  compress?: boolean;
}

export interface UdpSocketOptions {
  host: string;
  port: number;
  bind?: boolean;
  logger?: Logger;
}

// ---------------------------------------------------------------------------
// TCP connPiper
// ---------------------------------------------------------------------------

export function connPiper(
  connection: net.Socket,
  _dst: () => net.Socket | null,
  opts: PiperOptions = {},
  stats: PiperStats = {},
): void {
  const logger = opts.logger || { log() {} };
  logger.log({ type: 1, msg: 'Starting TCP connection piper' });
  const loc = _dst();
  if (loc === null) {
    logger.log({ type: 2, msg: 'Connection rejected (null destination)' });
    connection.destroy();
    if (!stats.rejectCnt) {
      stats.rejectCnt = 0;
    }
    stats.rejectCnt++;
    return;
  }
  if (!stats.locCnt) {
    stats.locCnt = 0;
  }
  if (!stats.remCnt) {
    stats.remCnt = 0;
  }
  stats.locCnt++;
  stats.remCnt++;

  let destroyed = false;

  loc.on('data', (d: Buffer) => {
    logger.log({ type: 0, msg: `Data from local to remote ${d.length} bytes` });
    connection.write(d);
  });

  connection.on('data', (d: Buffer) => {
    logger.log({ type: 0, msg: `Data from remote to local ${d.length} bytes` });
    loc.write(d);
  });

  loc.on('error', destroy).on('close', destroy);
  connection.on('error', destroy).on('close', destroy);

  loc.on('end', () => {
    logger.log({ type: 0, msg: 'Local end, ending connection' });
    connection.end();
  });

  connection.on('end', () => {
    logger.log({ type: 0, msg: 'Connection end, ending local' });
    loc.end();
  });

  loc.on('connect', (err?: Error) => {
    if (err) {
      logger.log({ type: 3, msg: err.message });
    } else {
      logger.log({ type: 1, msg: 'Connected' });
    }
  });

  function destroy(err?: Error) {
    if (destroyed) return;
    logger.log({
      type: 1,
      msg: `Destroying connection piper${err ? ` due to error ${err.message}` : ''}`,
    });
    stats.locCnt!--;
    stats.remCnt!--;
    destroyed = true;
    loc!.end();
    connection.end();
    loc!.destroy(err);
    connection.destroy(err);
    if (opts.onDestroy) {
      opts.onDestroy(err);
    }
  }
}

// ---------------------------------------------------------------------------
// UdpSocket
// ---------------------------------------------------------------------------

export class UdpSocket {
  opts: UdpSocketOptions;
  logger: Logger;
  server: Socket;
  client: Socket;
  event: EventEmitter;
  rinfo: { address: string; port: number } | null;

  constructor(opts: UdpSocketOptions) {
    this.opts = opts;
    this.logger = opts.logger || { log() {} };
    this.server = dgram.createSocket('udp4');
    this.client = dgram.createSocket('udp4');
    this.event = new EventEmitter();
    this.rinfo = null;
    this.connect();
    this.logger.log({
      type: 1,
      msg: `UDP socket created${opts.bind ? `, binding to ${opts.host}:${opts.port}` : ''}`,
    });
  }

  connect(): void {
    if (this.opts.bind) {
      this.server.bind(this.opts.port, this.opts.host);
    }

    this.server.on('message', (msg: Buffer, rinfo: { address: string; port: number }) => {
      this.logger.log({
        type: 0,
        msg: `UDP message from server ${msg.length} bytes from ${rinfo.address}:${rinfo.port}`,
      });
      this.event.emit('message', msg, rinfo);
      this.rinfo = rinfo;
    });

    this.client.on('message', (response: Buffer) => {
      this.logger.log({
        type: 0,
        msg: `UDP message from client ${response.length} bytes from ${this.opts.host}:${this.opts.port}`,
      });
      this.event.emit('message', response);
    });

    this.client.on('error', (err: Error) => {
      this.logger.log({ type: 3, msg: `UDP error ${err.stack}` });
      this.client.close();
    });
  }

  write(msg: Buffer): void {
    this.logger.log({ type: 0, msg: `Writing UDP message ${msg.length} bytes` });
    if (this.rinfo) {
      this.server.send(msg, 0, msg.length, this.rinfo.port, this.rinfo.address);
    } else {
      this.client.send(msg, 0, msg.length, this.opts.port, this.opts.host);
    }
  }
}

// ---------------------------------------------------------------------------
// UdpConnPiper
// ---------------------------------------------------------------------------

export interface UdpConnPiperOptions {
  client?: boolean;
  retryDelay?: number;
  logger?: Logger;
}

export class UdpConnPiper {
  opts: UdpConnPiperOptions;
  logger: Logger;
  remote: net.Socket | (() => net.Socket | null);
  local: UdpSocket | (() => UdpSocket | null);
  client: boolean | undefined;
  retryDelay: number;
  destroyed: boolean;
  localStream: UdpSocket | null = null;
  remoteStream: net.Socket | null = null;
  bound: {
    onLocMessage: (msg: Buffer, rinfo: { address: string; port: number }) => void;
    onConnectionMessage: (msg: Buffer) => void;
    onLocError: (err?: Error) => void;
    onLocClose: (err?: Error) => void;
    onConnectionError: (err?: Error) => void;
    onConnectionClose: (err?: Error) => void;
  };

  constructor(
    remote: net.Socket | (() => net.Socket | null),
    local: UdpSocket | (() => UdpSocket | null),
    opts: UdpConnPiperOptions = {},
  ) {
    this.opts = opts;
    this.logger = opts.logger || { log() {} };
    this.remote = remote;
    this.local = local;
    this.client = opts.client;
    this.retryDelay = opts.retryDelay || 2000;
    this.destroyed = false;
    this.bound = {
      onLocMessage: this.onLocMessage.bind(this),
      onConnectionMessage: this.onConnectionMessage.bind(this),
      onLocError: this._handleError.bind(this),
      onLocClose: this._handleError.bind(this),
      onConnectionError: this._handleError.bind(this),
      onConnectionClose: this._handleError.bind(this),
    };
    this.connect();
    this.logger.log({
      type: 1,
      msg: `Starting UDP connection piper${opts.client ? ' (client mode)' : ' (server mode)'}`,
    });
  }

  connect(): void {
    if (this.destroyed) return;
    this.logger.log({ type: 0, msg: 'Connecting UDP piper' });
    this.removeListeners();
    this.localStream = typeof this.local === 'function' ? this.local() : this.local;
    this.remoteStream = typeof this.remote === 'function' ? (this.remote as () => net.Socket | null)() : this.remote as net.Socket;
    if (!this.localStream || !this.remoteStream) {
      this.logger.log({ type: 2, msg: 'UDP connect failed (missing streams)' });
      this.destroy();
      return;
    }
    this.attachListeners();
  }

  attachListeners(): void {
    (this.localStream as UdpSocket).event.on('message', this.bound.onLocMessage);
    (this.localStream as UdpSocket).server.on('error', this.bound.onLocError);
    (this.localStream as UdpSocket).server.on('close', this.bound.onLocClose);
    (this.remoteStream as net.Socket).on('message' as any, this.bound.onConnectionMessage);
    (this.remoteStream as net.Socket).on('error', this.bound.onConnectionError);
    (this.remoteStream as net.Socket).on('close', this.bound.onConnectionClose);
    this.logger.log({ type: 0, msg: 'UDP listeners attached' });
  }

  removeListeners(): void {
    if (this.localStream) {
      this.localStream.event.off('message', this.bound.onLocMessage);
      this.localStream.server.off('error', this.bound.onLocError);
      this.localStream.server.off('close', this.bound.onLocClose);
    }
    if (this.remoteStream) {
      (this.remoteStream as net.Socket).off('message' as any, this.bound.onConnectionMessage);
      (this.remoteStream as net.Socket).off('error', this.bound.onConnectionError);
      (this.remoteStream as net.Socket).off('close', this.bound.onConnectionClose);
    }
    this.logger.log({ type: 0, msg: 'UDP listeners removed' });
  }

  onLocMessage(msg: Buffer, rinfo: { address: string; port: number }): void {
    this.logger.log({ type: 0, msg: `UDP message from local ${msg.length} bytes` });
    if (this.remoteStream && !this.destroyed) {
      (this.remoteStream as net.Socket).write(msg);
    }
  }

  onConnectionMessage(msg: Buffer): void {
    this.logger.log({ type: 0, msg: `UDP message from connection ${msg.length} bytes` });
    if (this.localStream && !this.destroyed) {
      this.localStream.write(msg);
    }
  }

  _handleError(err?: Error): void {
    this.logger.log({ type: 2, msg: `UDP error ${err ? err.message : 'close'}` });
    this.destroy(err);
  }

  destroy(err?: Error): void {
    if (this.destroyed) return;
    this.destroyed = true;
    this.logger.log({
      type: 1,
      msg: `Destroying UDP piper${err ? ` due to error ${err.message}` : ''}`,
    });
    this.removeListeners();
    try {
      (this.localStream as UdpSocket)?.server?.close?.();
    } catch {
      // ignore
    }
    try {
      (this.remoteStream as net.Socket)?.destroy?.(err);
    } catch {
      // ignore
    }
    if (this.client) {
      this.logger.log({ type: 1, msg: `Scheduling retry in ${this.retryDelay}ms` });
      setTimeout(() => {
        this.destroyed = false;
        this.connect();
      }, this.retryDelay);
    }
  }
}

// ---------------------------------------------------------------------------
// Factory functions
// ---------------------------------------------------------------------------

export function udpConnect(
  opts: UdpSocketOptions,
  callback?: (socket: UdpSocket) => void,
): UdpSocket | undefined {
  const socket = new UdpSocket(opts);
  if (typeof callback === 'function') {
    callback(socket);
    return;
  }
  return socket;
}

export function udpPiper(
  connection: net.Socket,
  _dst: UdpSocket | (() => UdpSocket | null),
  opts?: UdpConnPiperOptions,
): UdpConnPiper {
  return new UdpConnPiper(connection, _dst, opts);
}

export interface ListenOptions {
  port: number;
  host: string;
}

export function createTcpProxy(
  listenOpts: ListenOptions,
  connectRemote: () => net.Socket | null,
  piperOpts?: PiperOptions,
  stats?: PiperStats,
  onListen?: () => void,
): Server {
  const proxy = net.createServer({ allowHalfOpen: true }, (c: net.Socket) => {
    connPiper(c, connectRemote, piperOpts, stats);
  });
  proxy.listen(listenOpts.port, listenOpts.host, onListen);
  return proxy;
}

export function pipeTcpServer(
  remoteStream: net.Socket,
  localOpts: ListenOptions,
  piperOpts?: PiperOptions,
  stats?: PiperStats,
): void {
  connPiper(
    remoteStream,
    () =>
      net.connect({
        port: localOpts.port,
        host: localOpts.host,
        allowHalfOpen: true,
      }),
    piperOpts,
    stats,
  );
}

export interface FramedProxyResult {
  proxySocket: Socket;
  clients: Map<string, FramedClient>;
}

export interface FramedClient {
  remoteStream: net.Socket;
  rinfo: { address: string; port: number };
  buffer: Buffer;
}

export function createUdpFramedProxy(
  listenOpts: ListenOptions,
  connectRemote: () => net.Socket,
  logger: Logger,
  onBind?: () => void,
): FramedProxyResult {
  const proxySocket = dgram.createSocket('udp4');
  const clients = new Map<string, FramedClient>();

  proxySocket.on('error', (err: Error) => {
    logger.log({ type: 3, msg: `Proxy socket error ${err.stack}` });
    proxySocket.close();
  });

  proxySocket.on('message', (msg: Buffer, rinfo: { address: string; port: number }) => {
    const clientId = `${rinfo.address}:${rinfo.port}`;
    logger.log({ type: 0, msg: `UDP message from ${clientId} ${msg.length} bytes` });
    let client = clients.get(clientId);
    if (!client) {
      const remoteStream = connectRemote();
      client = { remoteStream, rinfo, buffer: Buffer.alloc(0) };
      clients.set(clientId, client);

      remoteStream.on('data', (chunk: Buffer) => {
        if (!client) return;
        client.buffer = Buffer.concat([client.buffer, chunk]);
        while (client.buffer.length >= 4) {
          const len = client.buffer.readUInt32BE(0);
          if (client.buffer.length < 4 + len) break;
          const response = client.buffer.slice(4, 4 + len);
          logger.log({
            type: 0,
            msg: `UDP response for ${clientId} ${response.length} bytes`,
          });
          proxySocket.send(
            response,
            0,
            response.length,
            rinfo.port,
            rinfo.address,
            (err?: Error | null) => {
              if (err)
                logger.log({ type: 3, msg: `Send error to ${clientId} ${err.stack}` });
            },
          );
          client.buffer = client.buffer.slice(4 + len);
        }
      });

      remoteStream.on('error', (err: Error) => {
        logger.log({ type: 3, msg: `Remote error for ${clientId} ${err.stack}` });
        if (client) {
          clients.delete(clientId);
          remoteStream.destroy();
        }
      });

      remoteStream.on('close', () => {
        logger.log({ type: 0, msg: `Remote close for ${clientId}` });
        clients.delete(clientId);
      });
    }

    const lenBuf = Buffer.alloc(4);
    lenBuf.writeUInt32BE(msg.length, 0);
    client.remoteStream.write(Buffer.concat([lenBuf, msg]));
  });

  proxySocket.bind(listenOpts.port, listenOpts.host, onBind);

  return { proxySocket, clients };
}

export function pipeUdpFramedServer(
  remoteStream: net.Socket,
  localOpts: ListenOptions,
  logger: Logger,
  _stats?: PiperStats,
): void {
  const localSocket = dgram.createSocket('udp4');
  let buffer = Buffer.alloc(0);

  localSocket.on('error', (err: Error) => {
    logger.log({ type: 3, msg: `Local UDP socket error ${err.stack}` });
    remoteStream.destroy(err);
  });

  localSocket.on('message', (msg: Buffer) => {
    logger.log({ type: 0, msg: `Data from local to remote ${msg.length} bytes` });
    const lenBuf = Buffer.alloc(4);
    lenBuf.writeUInt32BE(msg.length, 0);
    remoteStream.write(Buffer.concat([lenBuf, msg]));
  });

  remoteStream.on('data', (chunk: Buffer) => {
    logger.log({ type: 0, msg: `Data from remote to local ${chunk.length} bytes` });
    buffer = Buffer.concat([buffer, chunk]);
    while (buffer.length >= 4) {
      const len = buffer.readUInt32BE(0);
      if (buffer.length < 4 + len) break;
      const msg = buffer.slice(4, 4 + len);
      localSocket.send(
        msg,
        0,
        msg.length,
        localOpts.port,
        localOpts.host,
        (err?: Error | null) => {
          if (err) logger.log({ type: 3, msg: `Send error to local ${err.stack}` });
        },
      );
      buffer = buffer.slice(4 + len);
    }
  });

  remoteStream.on('end', () => localSocket.close());
  localSocket.on('close', () => remoteStream.end());
  remoteStream.on('error', () => localSocket.close());
  localSocket.on('error', () => remoteStream.destroy());
}
